> import android.util.Log;
> 
> import com.termux.shared.termux.TermuxConstants;
> import com.termux.shared.termux.TermuxConstants.TERMUX_APP.RUN_COMMAND_SERVICE;
> 
> import java.util.ArrayList;
> import java.util.List;
> 
> public class Termux {
>     public static void ExecuteCommand (Context appContext, String commandLine) {
>         String[] commandLineChunks = null;
>         List<String> args = null;
>         String command = null;
> 
>         if (commandLine == null) {
>             Log.e ("", ""); // TODO
> 
>         } else {
>             commandLine = commandLine.trim();
> 
>             if (commandLine.length() == 0) {
>                 Log.e ("", ""); // TODO
> 
>             } else {
>                 commandLineChunks = commandLine.split(" ");
> 
>                 command = commandLineChunks[0];
>                 args = new ArrayList<String>();
> 
>                 for (int c = 1; c < commandLineChunks.length; c ++) {
>                     args.add(commandLineChunks[c]);
>                 }                
> 
>                 // Create a request for the Termux app for executing a command line.
>                 Intent termuxRequest = new Intent();
>                 termuxRequest.setClassName(TermuxConstants.TERMUX_PACKAGE_NAME, TermuxConstants.TERMUX_APP.RUN_COMMAND_SERVICE_NAME);
>                 termuxRequest.setAction(RUN_COMMAND_SERVICE.ACTION_RUN_COMMAND);
> 
>                 termuxRequest.putExtra(RUN_COMMAND_SERVICE.EXTRA_COMMAND_PATH, "/data/data/com.termux/files/usr/bin/" + command);
>                 termuxRequest.putExtra(RUN_COMMAND_SERVICE.EXTRA_ARGUMENTS, args.toArray());
>                 termuxRequest.putExtra(RUN_COMMAND_SERVICE.EXTRA_WORKDIR, "/data/data/com.termux/files/home");
>                 termuxRequest.putExtra(RUN_COMMAND_SERVICE.EXTRA_BACKGROUND, true);
>                 termuxRequest.putExtra(RUN_COMMAND_SERVICE.EXTRA_SESSION_ACTION, 0);
>                 termuxRequest.putExtra(RUN_COMMAND_SERVICE.EXTRA_COMMAND_LABEL, "uname command");
>                 termuxRequest.putExtra(RUN_COMMAND_SERVICE.EXTRA_COMMAND_DESCRIPTION, "Command test.");
>                 
> 
>                 // The Termux app will use this PendingIntent to send the command line execution result.
>                 Intent resultsServiceIntent = new Intent(appContext, TermuxResultService.class);
> 
>                 int executionId = TermuxResultService.getNextExecutionId();
> 
>                 PendingIntent termuxResponse = PendingIntent.getService(appContext, executionId, resultsServiceIntent, PendingIntent.FLAG_ONE_SHOT);
> 
>                 termuxRequest.putExtra(RUN_COMMAND_SERVICE.EXTRA_PENDING_INTENT, termuxResponse);
> 
> 
>                 try {
>                     Log.i("Termux", "Executing command line '" + commandLine + "' with id " + executionId);
> 
> 
>                     // Sends the Termux app the created request
>                     if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
>                         appContext.startForegroundService(termuxRequest);
> 
>                     } else {
>                         appContext.startService(termuxRequest);
>                     }
> 
>                     Log.i("TERMUX_COMMAND_RESULT", resultsServiceIntent.getStringExtra("STDOUT"));
> 
>                 } catch (Exception e) {
>                     Log.e("Termux", "Failed executing '" + commandLine + "' with id " + executionId + ": " + e.getMessage());
>                 }
>             }
>         }
>     }
> }


And here the MainActivity:

> 
> package me.ariaththesage.android.libs.termuxmodule.testapp;
> 
> import androidx.appcompat.app.AppCompatActivity;
> 
